public int[] fix45(int[] nums) {
    int i = 0;
    int j = 0;

    while (j < nums.length && nums[j] != 4) {
        j++;
    }

    while (i < nums.length) {
        if (nums[i] == 4) {
            if (nums[i + 1] != 5) {
                int temp = nums[i + 1];
                nums[i + 1] = 5;
                for (int k = j; k < nums.length - 1; k++) {
                    if (nums[k] == 5 && nums[k + 1] == 4) {
                        nums[k + 1] = temp;
                        break;
                    }
                }
            }
            i++;
        } else {
            i++;
        }
    }

    return nums;
}

