public boolean twoTwo(int[] nums) {
    int n = nums.length;

    if (n < 2) {
        return n != 1 || nums[0] != 2;
    }

    for (int i = 0; i < n; i++) {
        if (nums[i] == 2) {
            if ((i > 0 && nums[i - 1] == 2) || (i < n - 1 && nums[i + 1] == 2)) {
                continue;
            } else {
                return false;
            }
        }
    }

    return true;
}

