public int blackjack(int a, int b) {
    if (a > 21 && b > 21) {
        return 0;
    } else if (a > 21) {
        return b;
    } else if (b > 21) {
        return a;
    } else {
        if (21 - a >= 0 && 21 - b >= 0) {
            if (21 - a <= 21 - b) {
                return a;
            } else {
                return b;
            }
        } else if (21 - a >= 0) {
            return a;
        } else {
            return b;
        }
    }
}

public int centeredAverage(int[] nums) {
    int sum = 0;
    int min = Integer.MAX_VALUE;
    int max = Integer.MIN_VALUE;
    int minCount = 0;
    int maxCount = 0;

    for (int num : nums) {
        sum += num;
        if (num < min) {
            min = num;
            minCount = 1;
        } else if (num == min) {
            minCount++;
        }
        if (num > max) {
            max = num;
            maxCount = 1;
        } else if (num == max) {
            maxCount++;
        }
    }

    int totalCount = nums.length - minCount - maxCount;
    int centralSum = sum - (min * minCount) - (max * maxCount);
    return centralSum / totalCount;
}

