public boolean xyBalance(String str) {
    int lastIndexX = -1;
    int lastIndexY = -1;

    for (int i = str.length() - 1; i >= 0; i--) {
        char currentChar = str.charAt(i);
        if (currentChar == 'x' && lastIndexY == -1) {
            lastIndexX = i;
        } else if (currentChar == 'y') {
            lastIndexY = i;
            break;
        }
    }

    return lastIndexX <= lastIndexY;
}

