public int blackjack(int a, int b) {
    if (a > 21 && b > 21) {
        return 0;
    } else if (a > 21) {
        return b;
    } else if (b > 21) {
        return a;
    } else {
        if (21 - a >= 0 && 21 - a < 21 - b) {
            return a;
        } else {
            return b;
        }
    }
}

public String repeatEnd(String str, int n) {
    if(n == 0) {
        return "";
    } else {
        int len = str.length();
        String endSubstring = str.substring(len - n);
        StringBuilder result = new StringBuilder();

        for(int i = 0; i < n; i++) {
            result.append(endSubstring);
        }

        return result.toString();
    }
}

