public int[] fix45(int[] nums) {
    int i = 0;
    while (i < nums.length && (nums[i] != 4 || (i > 0 && nums[i - 1] == 4))) {
        i++;
    }

    int j = 0;
    while (j < nums.length) {
        if (nums[j] == 5 && (j == 0 || nums[j - 1] == 4)) {
            j++;
        } else if (nums[j] == 4) {
            if (nums[i] != 5) {
                int temp = nums[i];
                nums[i] = nums[j + 1];
                nums[j + 1] = temp;
            }
            i++;
        }
        j++;
    }

    return nums;
}

