public boolean xyBalance(String str) {
    int lastIndexX = -1;
    int lastIndexY = -1;

    for (int i = str.length() - 1; i >= 0; i--) {
        char currentChar = str.charAt(i);
        if (currentChar == 'x') {
            lastIndexX = i;
        } else if (currentChar == 'y') {
            lastIndexY = i;
            if (lastIndexY > lastIndexX) {
                return true;
            }
        }
    }

    return lastIndexY >= lastIndexX;
}

