public int[] fix45(int[] nums) {
  int i = 0;
  while (i < nums.length && nums[i] != 4) {
    i++;
  }

  int j = i + 1;
  while (j < nums.length) {
    if (nums[j] == 5 && (j == 0 || nums[j - 1] != 4)) {
      int temp = nums[i + 1];
      nums[i + 1] = nums[j];
      nums[j] = temp;
    }
    j++;
  }

  for (j = 0; j < nums.length; j++) {
    if (nums[j] == 5 && (j == 0 || nums[j - 1] != 4)) {
      for (int k = 0; k < nums.length; k++) {
        if (nums[k] == 4 && nums[k + 1] != 5) {
          int temp = nums[j];
          nums[j] = nums[k + 1];
          nums[k + 1] = temp;
        }
      }
    }
  }

  return nums;
}

