public int blackjack(int a, int b) {
    if (a > 21 && b > 21) {
        return 0;
    } else if (a > 21) {
        return b;
    } else if (b > 21) {
        return a;
    } else {
        int diffA = 21 - a;
        int diffB = 21 - b;

        if (diffA < diffB) {
            return a;
        } else {
            return b;
        }
    }
}

public int[] fix45(int[] nums) {
    int i = 0;
    int j = 0;

    while (j < nums.length && nums[j] != 5) {
        j++;
    }

    while (i < nums.length) {
        if (nums[i] == 4) {
            if (nums[i + 1] != 5) {
                int temp = nums[i + 1];
                nums[i + 1] = 5;
                for (int k = j; k < nums.length; k++) {
                    if (nums[k] == 5 && (k == 0 || nums[k - 1] != 4)) {
                        nums[k] = temp;
                        break;
                    }
                }
            }
        }
        i++;
    }

    return nums;
}

