public int caughtSpeeding(int speed, boolean isBirthday) {
    int lowerLimit = 60;
    int upperLimit = 80;

    if (isBirthday) {
        lowerLimit += 5;
        upperLimit += 5;
    }

    if (speed <= lowerLimit) {
        return 0;
    } else if (speed >= lowerLimit + 1 && speed <= upperLimit) {
        return 1;
    } else {
        return 2;
    }
}

