        j++;
    }

    while (i < nums.length) {
        if (nums[i] == 4) {
            if (nums[i + 1] != 5) {
                int temp = nums[i + 1];
                nums[i + 1] = 5;
                nums[j] = temp;
            }
            i++;
            j++;
        } else {
            i++;
        }
    }

    return nums;
}

