public int[] fix45(int[] nums) {
    int i = 0;
    while (i < nums.length && nums[i] != 4) {
        i++;
    }

    int j = 0;
    while (j < nums.length) {
        if (nums[j] == 5 && (j == 0 || nums[j - 1] != 4)) {
            if (i < nums.length && nums[i] != 5) {
                int temp = nums[i];
                nums[i] = 5;
                nums[j] = temp;
                i++;
            }
        }
        j++;
    }

    return nums;
}

