    boolean isBalanced = true;
    boolean foundY = false;

    for (int i = str.length() - 1; i >= 0; i--) {
        char currentChar = str.charAt(i);

        if (currentChar == 'y') {
            foundY = true;
        }

        if (currentChar == 'x' && !foundY) {
            isBalanced = false;
            break;
        }
    }

    return isBalanced;
}

