public boolean xyzThere(String str) {
    int len = str.length();
    for (int i = 0; i < len - 2; i++) {
        if (str.charAt(i) != '.' && str.substring(i, i + 3).equals("xyz")) {
            return true;
        }
    }
    if (len >= 3 && str.substring(len - 3).equals("xyz")) {
        return true;
    }
    return false;
}

