public int[] tenRun(int[] nums) {
    if (nums.length == 0) {
        return nums;
    }

    int multipleOfTen = 0;
    boolean foundMultipleOfTen = false;

    for (int i = 0; i < nums.length; i++) {
        if (nums[i] % 10 == 0) {
            multipleOfTen = nums[i];
            foundMultipleOfTen = true;
        } else if (foundMultipleOfTen) {
            nums[i] = multipleOfTen;
        }
    }

    return nums;
}

