public int[] fix45(int[] nums) {
    int i = 0;
    int j = 0;

    while (j < nums.length && nums[j] != 5) {
        if (nums[i] == 4) {
            while (nums[j] == 4 || (j > 0 && nums[j - 1] == 4) || nums[j] == 5) {
                j++;
            }

            if (nums[j] == 5) {
                int temp = nums[j];
                nums[j] = nums[i + 1];
                nums[i + 1] = temp;
            } else {
                int k = i + 1;
                while (nums[k] != 5 || (k > 0 && nums[k - 1] == 4)) {
                    k++;
                }
                int temp = nums[k];
                nums[k] = nums[i + 1];
                nums[i + 1] = temp;
            }
        }
        i++;
        j++;
    }

    return nums;
}

